61: /**
62:  * This class acts as a queue that accumulates records into {@link MemoryRecords}
63:  * instances to be sent to the server.
64:  * <p>
65:  * The accumulator uses a bounded amount of memory and append calls will block when that memory is exhausted, unless
66:  * this behavior is explicitly disabled.
67:  */
68: public class RecordAccumulator {
69: 
70:     private final LogContext logContext;
71:     private final Logger log;
72:     private volatile boolean closed;
73:     private final AtomicInteger flushesInProgress;
74:     private final AtomicInteger appendsInProgress;
75:     private final int batchSize;
76:     private final Compression compression;
77:     private final int lingerMs;
78:     private final ExponentialBackoff retryBackoff;
79:     private final int deliveryTimeoutMs;
80:     private final long partitionAvailabilityTimeoutMs;  // latency threshold for marking partition temporary unavailable
81:     private final boolean enableAdaptivePartitioning;
82:     private final BufferPool free;
83:     private final Time time;
84:     private final ConcurrentMap<String /*topic*/, TopicInfo> topicInfoMap = new CopyOnWriteMap<>();
85:     private final ConcurrentMap<Integer /*nodeId*/, NodeLatencyStats> nodeStats = new CopyOnWriteMap<>();
86:     private final IncompleteBatches incomplete;
87:     // The following variables are only accessed by the sender thread, so we don't need to protect them.
88:     private final Set<TopicPartition> muted;
89:     private final Map<String, Integer> nodesDrainIndex;
90:     private final TransactionManager transactionManager;
91:     private long nextBatchExpiryTimeMs = Long.MAX_VALUE; // the earliest time (absolute) a batch will expire.
92: 
93:     /**
94:      * Create a new record accumulator
95:      *
96:      * @param logContext The log context used for logging
97:      * @param batchSize The size to use when allocating {@link MemoryRecords} instances
98:      * @param compression The compression codec for the records
99:      * @param lingerMs An artificial delay time to add before declaring a records instance that isn't full ready for
100:      *        sending. This allows time for more records to arrive. Setting a non-zero lingerMs will trade off some
101:      *        latency for potentially better throughput due to more batching (and hence fewer, larger requests).
102:      * @param retryBackoffMs An artificial delay time to retry the produce request upon receiving an error. This avoids
103:      *        exhausting all retries in a short period of time.
104:      * @param retryBackoffMaxMs The upper bound of the retry backoff time.
105:      * @param deliveryTimeoutMs An upper bound on the time to report success or failure on record delivery
106:      * @param partitionerConfig Partitioner config
107:      * @param metrics The metrics
108:      * @param metricGrpName The metric group name
109:      * @param time The time instance to use
110:      * @param transactionManager The shared transaction state object which tracks producer IDs, epochs, and sequence
111:      *                           numbers per partition.
112:      * @param bufferPool The buffer pool
113:      */
114:     public RecordAccumulator(LogContext logContext,
115:                              int batchSize,
116:                              Compression compression,
117:                              int lingerMs,
118:                              long retryBackoffMs,
119:                              long retryBackoffMaxMs,
120:                              int deliveryTimeoutMs,
121:                              PartitionerConfig partitionerConfig,
122:                              Metrics metrics,
123:                              String metricGrpName,
124:                              Time time,
125:                              TransactionManager transactionManager,
126:                              BufferPool bufferPool) {
127:         this.logContext = logContext;
128:         this.log = logContext.logger(RecordAccumulator.class);
129:         this.closed = false;
130:         this.flushesInProgress = new AtomicInteger(0);
131:         this.appendsInProgress = new AtomicInteger(0);
132:         this.batchSize = batchSize;
133:         this.compression = compression;
134:         this.lingerMs = lingerMs;
135:         this.retryBackoff = new ExponentialBackoff(retryBackoffMs,
136:                 CommonClientConfigs.RETRY_BACKOFF_EXP_BASE,
137:                 retryBackoffMaxMs,
138:                 CommonClientConfigs.RETRY_BACKOFF_JITTER);
139:         this.deliveryTimeoutMs = deliveryTimeoutMs;
140:         this.enableAdaptivePartitioning = partitionerConfig.enableAdaptivePartitioning;
141:         this.partitionAvailabilityTimeoutMs = partitionerConfig.partitionAvailabilityTimeoutMs;
142:         this.free = bufferPool;
143:         this.incomplete = new IncompleteBatches();
144:         this.muted = new HashSet<>();
145:         this.time = time;
146:         nodesDrainIndex = new HashMap<>();
147:         this.transactionManager = transactionManager;
148:         registerMetrics(metrics, metricGrpName);
149:     }
150: 
151:     /**
152:      * Create a new record accumulator with default partitioner config
153:      *
154:      * @param logContext The log context used for logging
155:      * @param batchSize The size to use when allocating {@link MemoryRecords} instances
156:      * @param compression The compression codec for the records
157:      * @param lingerMs An artificial delay time to add before declaring a records instance that isn't full ready for
158:      *        sending. This allows time for more records to arrive. Setting a non-zero lingerMs will trade off some
159:      *        latency for potentially better throughput due to more batching (and hence fewer, larger requests).
160:      * @param retryBackoffMs An artificial delay time to retry the produce request upon receiving an error. This avoids
161:      *        exhausting all retries in a short period of time.
162:      * @param retryBackoffMaxMs The upper bound of the retry backoff time.
163:      * @param deliveryTimeoutMs An upper bound on the time to report success or failure on record delivery
164:      * @param metrics The metrics
165:      * @param metricGrpName The metric group name
166:      * @param time The time instance to use
167:      * @param transactionManager The shared transaction state object which tracks producer IDs, epochs, and sequence
168:      *                           numbers per partition.
169:      * @param bufferPool The buffer pool
170:      */
171:     public RecordAccumulator(LogContext logContext,
172:                              int batchSize,
173:                              Compression compression,
174:                              int lingerMs,
175:                              long retryBackoffMs,
176:                              long retryBackoffMaxMs,
177:                              int deliveryTimeoutMs,
178:                              Metrics metrics,
179:                              String metricGrpName,
180:                              Time time,
181:                              TransactionManager transactionManager,
182:                              BufferPool bufferPool) {
183:         this(logContext,
184:             batchSize,
185:             compression,
186:             lingerMs,
187:             retryBackoffMs,
188:             retryBackoffMaxMs,
189:             deliveryTimeoutMs,
190:             new PartitionerConfig(),
191:             metrics,
192:             metricGrpName,
193:             time,
194:             transactionManager,
195:             bufferPool);
196:     }
