492:     /**
493:      * Re-enqueue the given record batch in the accumulator. In Sender.completeBatch method, we check
494:      * whether the batch has reached deliveryTimeoutMs or not. Hence we do not do the delivery timeout check here.
495:      */
496:     public void reenqueue(ProducerBatch batch, long now) {
497:         batch.reenqueued(now);
498:         Deque<ProducerBatch> deque = getOrCreateDeque(batch.topicPartition);
499:         synchronized (deque) {
500:             if (transactionManager != null)
501:                 insertInSequenceOrder(deque, batch);
502:             else
503:                 deque.addFirst(batch);
504:         }
505:     }
