589:     /**
590:      * Add the leader to the ready nodes if the batch is ready
591:      *
592:      * @param exhausted 'true' is the buffer pool is exhausted
593:      * @param part The partition
594:      * @param leader The leader for the partition
595:      * @param waitedTimeMs How long batch waited
596:      * @param backingOff Is backing off
597:      * @param backoffAttempts Number of attempts for calculating backoff delay
598:      * @param full Is batch full
599:      * @param nextReadyCheckDelayMs The delay for next check
600:      * @param readyNodes The set of ready nodes (to be filled in)
601:      * @return The delay for next check
602:      */
603:     private long batchReady(boolean exhausted, TopicPartition part, Node leader,
604:                             long waitedTimeMs, boolean backingOff, int backoffAttempts,
605:                             boolean full, long nextReadyCheckDelayMs, Set<Node> readyNodes) {
606:         if (!readyNodes.contains(leader) && !isMuted(part)) {
607:             long timeToWaitMs = backingOff ? retryBackoff.backoff(backoffAttempts > 0 ? backoffAttempts - 1 : 0) : lingerMs;
608:             boolean expired = waitedTimeMs >= timeToWaitMs;
609:             boolean transactionCompleting = transactionManager != null && transactionManager.isCompleting();
610:             boolean sendable = full
611:                     || expired
612:                     || exhausted
613:                     || closed
614:                     || flushInProgress()
615:                     || transactionCompleting;
616:             if (sendable && !backingOff) {
617:                 readyNodes.add(leader);
618:             } else {
619:                 long timeLeftMs = Math.max(timeToWaitMs - waitedTimeMs, 0);
620:                 // Note that this results in a conservative estimate since an un-sendable partition may have
621:                 // a leader that will later be found to have sendable data. However, this is good enough
622:                 // since we'll just wake up and then sleep again for the remaining time.
623:                 nextReadyCheckDelayMs = Math.min(timeLeftMs, nextReadyCheckDelayMs);
624:             }
625:         }
626:         return nextReadyCheckDelayMs;
627:     }
