847:     private List<ProducerBatch> drainBatchesForOneNode(MetadataSnapshot metadataSnapshot, Node node, int maxSize, long now) {
848:         int size = 0;
849:         List<PartitionInfo> parts = metadataSnapshot.cluster().partitionsForNode(node.id());
850:         List<ProducerBatch> ready = new ArrayList<>();
851:         if (parts.isEmpty())
852:             return ready;
853:         /* to make starvation less likely each node has it's own drainIndex */
854:         int drainIndex = getDrainIndex(node.idString());
855:         int start = drainIndex = drainIndex % parts.size();
856:         do {
857:             PartitionInfo part = parts.get(drainIndex);
858: 
859:             TopicPartition tp = new TopicPartition(part.topic(), part.partition());
860:             updateDrainIndex(node.idString(), drainIndex);
861:             drainIndex = (drainIndex + 1) % parts.size();
862:             // Only proceed if the partition has no in-flight batches.
863:             if (isMuted(tp))
864:                 continue;
865:             Deque<ProducerBatch> deque = getDeque(tp);
866:             if (deque == null)
867:                 continue;
868: 
869:             OptionalInt leaderEpoch = metadataSnapshot.leaderEpochFor(tp);
870: 
871:             final ProducerBatch batch;
872:             synchronized (deque) {
873:                 // invariant: !isMuted(tp,now) && deque != null
874:                 ProducerBatch first = deque.peekFirst();
875:                 if (first == null)
876:                     continue;
877: 
878:                 // first != null
879:                 // Only drain the batch if it is not during backoff period.
880:                 first.maybeUpdateLeaderEpoch(leaderEpoch);
881:                 if (shouldBackoff(first.hasLeaderChangedForTheOngoingRetry(), first, first.waitedTimeMs(now)))
882:                     continue;
883: 
884:                 if (size + first.estimatedSizeInBytes() > maxSize && !ready.isEmpty()) {
885:                     // there is a rare case that a single batch size is larger than the request size due to
886:                     // compression; in this case we will still eventually send this batch in a single request
887:                     break;
888:                 } else {
889:                     if (shouldStopDrainBatchesForPartition(first, tp))
890:                         break;
891:                 }
892: 
893:                 batch = deque.pollFirst();
894: 
895:                 boolean isTransactional = transactionManager != null && transactionManager.isTransactional();
896:                 ProducerIdAndEpoch producerIdAndEpoch =
897:                     transactionManager != null ? transactionManager.producerIdAndEpoch() : null;
898:                 if (producerIdAndEpoch != null && !batch.hasSequence()) {
899:                     // If the producer id/epoch of the partition do not match the latest one
900:                     // of the producer, we update it and reset the sequence. This should be
901:                     // only done when all its in-flight batches have completed. This is guarantee
902:                     // in `shouldStopDrainBatchesForPartition`.
903:                     transactionManager.maybeUpdateProducerIdAndEpoch(batch.topicPartition);
904: 
905:                     // If the batch already has an assigned sequence, then we should not change the producer id and
906:                     // sequence number, since this may introduce duplicates. In particular, the previous attempt
907:                     // may actually have been accepted, and if we change the producer id and sequence here, this
908:                     // attempt will also be accepted, causing a duplicate.
909:                     //
910:                     // Additionally, we update the next sequence number bound for the partition, and also have
911:                     // the transaction manager track the batch so as to ensure that sequence ordering is maintained
912:                     // even if we receive out of order responses.
913:                     batch.setProducerState(producerIdAndEpoch, transactionManager.sequenceNumber(batch.topicPartition), isTransactional);
914:                     transactionManager.incrementSequenceNumber(batch.topicPartition, batch.recordCount);
915:                     log.debug("Assigned producerId {} and producerEpoch {} to batch with base sequence " +
916:                             "{} being sent to partition {}", producerIdAndEpoch.producerId,
917:                         producerIdAndEpoch.epoch, batch.baseSequence(), tp);
918: 
919:                     transactionManager.addInFlightBatch(batch);
920:                 }
921:             }
922: 
923:             // the rest of the work by processing outside the lock
924:             // close() is particularly expensive
925:             batch.close();
926:             size += batch.records().sizeInBytes();
927:             ready.add(batch);
928: 
929:             batch.drained(now);
930:         } while (start != drainIndex);
931:         return ready;
932:     }
