1065:     /**
1066:      * Mark all partitions as ready to send and block until the send is complete
1067:      */
1068:     public void awaitFlushCompletion() throws InterruptedException {
1069:         try {
1070:             // Obtain a copy of all of the incomplete ProduceRequestResult(s) at the time of the flush.
1071:             // We must be careful not to hold a reference to the ProduceBatch(s) so that garbage
1072:             // collection can occur on the contents.
1073:             // The sender will remove ProducerBatch(s) from the original incomplete collection.
1074:             //
1075:             // We use awaitAllDependents() here instead of await() to ensure that if any batch
1076:             // was split into multiple batches, we wait for all the split batches to complete.
1077:             // This is required to guarantee that all records sent before flush()
1078:             // must be fully complete, including records in split batches.
1079:             for (ProduceRequestResult result : this.incomplete.requestResults())
1080:                 result.awaitAllDependents();
1081:         } finally {
1082:             this.flushesInProgress.decrementAndGet();
1083:         }
1084:     }
