1119:     /**
1120:      * Abort all incomplete batches (whether they have been sent or not)
1121:      */
1122:     void abortBatches(final RuntimeException reason) {
1123:         for (ProducerBatch batch : incomplete.copyAll()) {
1124:             Deque<ProducerBatch> dq = getDeque(batch.topicPartition);
1125:             synchronized (dq) {
1126:                 batch.abortRecordAppends();
1127:                 dq.remove(batch);
1128:             }
1129:             batch.abort(reason);
1130:             deallocate(batch);
1131:         }
1132:     }
1133: 
1134:     /**
1135:      * Abort any batches which have not been drained
1136:      */
1137:     void abortUndrainedBatches(RuntimeException reason) {
1138:         for (ProducerBatch batch : incomplete.copyAll()) {
1139:             Deque<ProducerBatch> dq = getDeque(batch.topicPartition);
1140:             boolean aborted = false;
1141:             synchronized (dq) {
1142:                 if ((transactionManager != null && !batch.hasSequence()) || (transactionManager == null && !batch.isClosed())) {
1143:                     aborted = true;
1144:                     batch.abortRecordAppends();
1145:                     dq.remove(batch);
1146:                 }
1147:             }
1148:             if (aborted) {
1149:                 batch.abort(reason);
1150:                 deallocate(batch);
1151:             }
1152:         }
1153:     }
